const listOpenPaymentReviews = `-- name: ListOpenPaymentReviews :many
SELECT id, payment_event_id, payment_id, order_id, wallet_topup_id, provider, provider_transaction_id, payment_reference, amount_vnd, currency, occurred_at, reason, status, resolution_note, resolved_by_admin_id, resolved_at, created_at, updated_at, payment_environment, event_source, provider_account_mapping_id, destination_account_identity FROM payment_review_cases
WHERE status IN ('open', 'held')
ORDER BY created_at, id
LIMIT $2::integer OFFSET $1::integer
`

type ListOpenPaymentReviewsParams struct {
	PageOffset int32 `db:"page_offset" json:"page_offset"`
	PageLimit  int32 `db:"page_limit" json:"page_limit"`
}

func (q *Queries) ListOpenPaymentReviews(ctx context.Context, arg ListOpenPaymentReviewsParams) ([]PaymentReviewCase, error) {
	rows, err := q.db.Query(ctx, listOpenPaymentReviews, arg.PageOffset, arg.PageLimit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []PaymentReviewCase{}
	for rows.Next() {
		var i PaymentReviewCase
		if err := rows.Scan(
			&i.ID,
			&i.PaymentEventID,
			&i.PaymentID,
			&i.OrderID,
			&i.WalletTopupID,
			&i.Provider,
			&i.ProviderTransactionID,
			&i.PaymentReference,
			&i.AmountVnd,
			&i.Currency,
			&i.OccurredAt,
			&i.Reason,
			&i.Status,
			&i.ResolutionNote,
			&i.ResolvedByAdminID,
			&i.ResolvedAt,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.PaymentEnvironment,
			&i.EventSource,
			&i.ProviderAccountMappingID,
			&i.DestinationAccountIdentity,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

